@Service
public class InventoryManagementSystem {

    @Autowired
    private JdbcTemplate jdbcTemplate;

    public void releaseStock(String orderId) {
        // Check if the compensating action has already been executed
        int count = jdbcTemplate.queryForObject("SELECT COUNT(*) FROM compensation_log WHERE order_id = ?", new Object[]{orderId}, Integer.class);

        if (count > 0) {
            return;
        }

        try {
            // Logic to release reserved stock
            System.out.println("Releasing stock for order " + orderId);

            // Record the compensating action in a log table
            jdbcTemplate.update("INSERT INTO compensation_log (order_id, action_type) VALUES (?, 'release_stock')", orderId);
        } catch (Exception e) {
            throw new RuntimeException("Failed to release stock: " + e.getMessage());
        }
    }

